import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';

const UserProfile: React.FC = () => {
  const { user, logout } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    nombre: user?.nombre || '',
    email: user?.email || '',
    telefono: user?.telefono || '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });

  const handleSave = () => {
    // Aquí iría la lógica para guardar los cambios
    setIsEditing(false);
  };

  const handleLogout = () => {
    logout();
  };

  return (
    <div className="page-inner">
      <div className="card">
        <div className="card-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 className="card-title">
              <i className="fas fa-user" style={{ marginRight: '10px' }}></i>
              Mi Perfil
            </h4>
            <div>
              {!isEditing ? (
                <button 
                  className="btn btn-primary"
                  onClick={() => setIsEditing(true)}
                >
                  <i className="fas fa-edit" style={{ marginRight: '8px' }}></i>
                  Editar
                </button>
              ) : (
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button 
                    className="btn btn-success"
                    onClick={handleSave}
                  >
                    <i className="fas fa-save" style={{ marginRight: '8px' }}></i>
                    Guardar
                  </button>
                  <button 
                    className="btn btn-secondary"
                    onClick={() => setIsEditing(false)}
                  >
                    Cancelar
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>

        <div style={{ padding: '25px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '30px' }}>
            {/* Avatar Section */}
            <div style={{ textAlign: 'center' }}>
              <div style={{
                width: '120px',
                height: '120px',
                borderRadius: '50%',
                background: 'linear-gradient(135deg, #1572e8, #0d47a1)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#ffffff',
                fontSize: '48px',
                fontWeight: '600',
                margin: '0 auto 20px'
              }}>
                {user?.nombre?.charAt(0).toUpperCase()}
              </div>
              <h5 style={{ color: '#1a2035', marginBottom: '5px' }}>{user?.nombre}</h5>
              <p style={{ color: '#6c757d', textTransform: 'capitalize' }}>{user?.rol}</p>

              <button 
                className="btn btn-danger"
                onClick={handleLogout}
                style={{ marginTop: '20px' }}
              >
                <i className="fas fa-sign-out-alt" style={{ marginRight: '8px' }}></i>
                Cerrar Sesión
              </button>
            </div>

            {/* Form Section */}
            <div>
              <div style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                  Nombre Completo
                </label>
                <input
                  type="text"
                  value={formData.nombre}
                  onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                  disabled={!isEditing}
                  style={{
                    width: '100%',
                    padding: '12px 15px',
                    border: '1px solid #ebedf2',
                    borderRadius: '8px',
                    fontSize: '14px',
                    background: isEditing ? '#ffffff' : '#f8f9fa'
                  }}
                />
              </div>

              <div style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                  Email
                </label>
                <input
                  type="email"
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                  disabled={!isEditing}
                  style={{
                    width: '100%',
                    padding: '12px 15px',
                    border: '1px solid #ebedf2',
                    borderRadius: '8px',
                    fontSize: '14px',
                    background: isEditing ? '#ffffff' : '#f8f9fa'
                  }}
                />
              </div>

              <div style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                  Teléfono
                </label>
                <input
                  type="tel"
                  value={formData.telefono}
                  onChange={(e) => setFormData({...formData, telefono: e.target.value})}
                  disabled={!isEditing}
                  style={{
                    width: '100%',
                    padding: '12px 15px',
                    border: '1px solid #ebedf2',
                    borderRadius: '8px',
                    fontSize: '14px',
                    background: isEditing ? '#ffffff' : '#f8f9fa'
                  }}
                />
              </div>

              {isEditing && (
                <>
                  <hr style={{ margin: '30px 0', border: 'none', borderTop: '1px solid #ebedf2' }} />
                  <h6 style={{ color: '#1a2035', marginBottom: '20px' }}>Cambiar Contraseña</h6>

                  <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                      Contraseña Actual
                    </label>
                    <input
                      type="password"
                      value={formData.currentPassword}
                      onChange={(e) => setFormData({...formData, currentPassword: e.target.value})}
                      style={{
                        width: '100%',
                        padding: '12px 15px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px'
                      }}
                    />
                  </div>

                  <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                      Nueva Contraseña
                    </label>
                    <input
                      type="password"
                      value={formData.newPassword}
                      onChange={(e) => setFormData({...formData, newPassword: e.target.value})}
                      style={{
                        width: '100%',
                        padding: '12px 15px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px'
                      }}
                    />
                  </div>

                  <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#1a2035' }}>
                      Confirmar Nueva Contraseña
                    </label>
                    <input
                      type="password"
                      value={formData.confirmPassword}
                      onChange={(e) => setFormData({...formData, confirmPassword: e.target.value})}
                      style={{
                        width: '100%',
                        padding: '12px 15px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px'
                      }}
                    />
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserProfile;
